6.3 dplyr：数据操作五大动词

6.3.1 filter() — 筛选行

# 筛选马尾松
survey |&gt;
  filter(species == "马尾松")

# 多条件筛选：株高 &gt; 15 且 土壤 pH &lt; 6
survey |&gt;
  filter(height &gt; 15, soil_ph &lt; 6)

# 或条件：马尾松或杉木
survey |&gt;
  filter(species %in% c("马尾松", "杉木"))



6.3.2 select() — 选择列

# 选择特定列
survey |&gt;
  select(plot_id, species, height)

# 排除某列
survey |&gt;
  select(-soil_ph)

# 选择数值列
survey |&gt;
  select(where(is.numeric))



6.3.3 mutate() — 新增/修改列

# 新增列：计算树木断面积（basal area）
survey |&gt;
  mutate(
    basal_area = pi * (dbh / 200)^2,    # 单位：m²
    height_class = case_when(
      is.na(height) ~ NA_character_,   # 先处理缺失值，避免被误判
      height &lt; 8    ~ "矮",
      height &lt; 15   ~ "中",
      TRUE          ~ "高"
    )
  ) |&gt;
  head()



6.3.4 arrange() — 排序

# 按株高降序排列
survey |&gt;
  arrange(desc(height)) |&gt;
  head()

# 先按样方排序，再按株高排序
survey |&gt;
  arrange(plot_id, desc(height)) |&gt;
  head()



6.3.5 summarise() + group_by() — 分组汇总

# 按物种分组统计
survey |&gt;
  group_by(species) |&gt;
  summarise(
    n = n(),
    mean_height = mean(height, na.rm = TRUE),
    sd_height = sd(height, na.rm = TRUE),
    mean_dbh = mean(dbh, na.rm = TRUE)
  ) |&gt;
  arrange(desc(mean_height))


# 按样方和生境分组
survey |&gt;
  group_by(habitat) |&gt;
  summarise(
    n_trees = n(),
    n_species = n_distinct(species),
    mean_ph = mean(soil_ph, na.rm = TRUE)
  )

16.6 统一数据格式

16.6.1 字符串清洗

# 查看 texture 列的唯一值
unique(soil_clean$texture)

# 统一格式：去空格、转小写
soil_clean &lt;- soil_clean |&gt;
  mutate(
    texture = texture |&gt;
      str_trim() |&gt;          # 去除首尾空格
      str_to_lower()         # 转为小写
  )

unique(soil_clean$texture)



16.6.2 日期格式统一

# 查看日期格式
unique(soil_clean$date)

# 使用 lubridate 统一日期格式
soil_clean &lt;- soil_clean |&gt;
  mutate(
    date = parse_date_time(date, orders = c("ymd", "y/m/d", "d-b-Y")) |&gt;
      as.Date()
  )

unique(soil_clean$date)
class(soil_clean$date)

16.8 完整的数据清洗流水线
将以上步骤整合为一个完整的流水线：

soil_final &lt;- soil_raw |&gt;
  # 1. 去重
  distinct() |&gt;
  # 2. 统一字符串格式
  mutate(
    texture = texture |&gt; str_trim() |&gt; str_to_lower()
  ) |&gt;
  # 3. 统一日期格式
  mutate(
    date = parse_date_time(date, orders = c("ymd", "y/m/d", "d-b-Y")) |&gt; as.Date()
  ) |&gt;
  # 4. 处理不合理的值（异常值 → NA）
  mutate(
    ph = if_else(ph &lt; 0 | ph &gt; 14, NA_real_, ph),
    organic_carbon = if_else(organic_carbon &lt; 0 | organic_carbon &gt; 100, NA_real_, organic_carbon),
    nitrogen = if_else(nitrogen &lt; 0, NA_real_, nitrogen)
  ) |&gt;
  # 5. 填充缺失值（中位数，此时异常值已移除，统计量更准确）
  mutate(
    ph = replace_na(ph, median(ph, na.rm = TRUE)),
    organic_carbon = replace_na(organic_carbon, median(organic_carbon, na.rm = TRUE)),
    nitrogen = replace_na(nitrogen, median(nitrogen, na.rm = TRUE))
  ) |&gt;
  # 6. 转换数据类型
  mutate(
    texture = factor(texture, levels = c("sand", "loam", "clay")),
    depth = factor(depth, levels = c("0-10", "10-20", "20-30"), ordered = TRUE)
  )

# 验证
summary(soil_final)

18.1 数据验证

18.1.1 范围检查
确保数值在合理范围内：

validate_soil &lt;- function(data) {
  issues &lt;- list()

  # pH 范围检查（0-14）
  bad_ph &lt;- data |&gt; filter(ph &lt; 0 | ph &gt; 14)
  if (nrow(bad_ph) &gt; 0) issues$ph &lt;- paste(nrow(bad_ph), "条 pH 超出范围")

  # 有机碳不能为负
  bad_oc &lt;- data |&gt; filter(organic_carbon &lt; 0)
  if (nrow(bad_oc) &gt; 0) issues$oc &lt;- paste(nrow(bad_oc), "条有机碳为负值")

  # 百分比之和检查
  if ("clay_pct" %in% names(data) && "sand_pct" %in% names(data)) {
    bad_pct &lt;- data |&gt; filter(clay_pct + sand_pct &gt; 100)
    if (nrow(bad_pct) &gt; 0) issues$pct &lt;- paste(nrow(bad_pct), "条粒径百分比之和超过100%")
  }

  if (length(issues) == 0) {
    cat("✅ 所有验证通过\n")
  } else {
    cat("⚠️ 发现以下问题：\n")
    for (name in names(issues)) {
      cat("  -", issues[[name]], "\n")
    }
  }

  invisible(issues)
}

# 示例
set.seed(2027)
soil &lt;- tibble(
  site_id = paste0("S", 1:10),
  ph = c(6.2, 5.8, 7.1, -0.5, 6.5, 15.2, 6.8, 5.9, 6.3, 7.0),
  organic_carbon = c(25, 30, 22, 28, -5, 35, 20, 27, 31, 24),
  clay_pct = c(30, 45, 20, 55, 40, 35, 25, 50, 38, 42),
  sand_pct = c(40, 30, 50, 60, 35, 45, 55, 30, 40, 35)
)

validate_soil(soil)



18.1.2 一致性检查

# 检查同一样点不同深度的数据是否一致
# 例如：表层有机碳应该高于深层
check_depth_consistency &lt;- function(data) {
  if (!("depth" %in% names(data))) return(invisible(NULL))

  inconsistent &lt;- data |&gt;
    group_by(site_id) |&gt;
    arrange(depth) |&gt;
    mutate(oc_decreasing = organic_carbon &lt; lag(organic_carbon)) |&gt;
    filter(!is.na(oc_decreasing) & !oc_decreasing) |&gt;
    ungroup()

  if (nrow(inconsistent) &gt; 0) {
    cat("⚠️", nrow(inconsistent), "条记录的有机碳未随深度递减（可能需要核实）\n")
  } else {
    cat("✅ 有机碳随深度递减，符合预期\n")
  }

  invisible(inconsistent)
}

# 示例：不同深度的土壤数据
soil_depth &lt;- tibble(
  site_id = rep(c("S1", "S2", "S3"), each = 3),
  depth = rep(c(10, 20, 30), 3),
  organic_carbon = c(
    35, 22, 15,   # S1: 正常递减
    28, 32, 18,   # S2: 20cm 处异常升高
    40, 30, 25    # S3: 正常递减
  )
)

check_depth_consistency(soil_depth)

20.5 描述性统计

20.5.1 集中趋势与离散程度

diversity |&gt;
  select(where(is.numeric)) |&gt;
  pivot_longer(everything(), names_to = "variable", values_to = "value") |&gt;
  group_by(variable) |&gt;
  summarise(
    n = n(),
    mean = round(mean(value), 2),
    sd = round(sd(value), 2),
    median = round(median(value), 2),
    min = round(min(value), 2),
    max = round(max(value), 2),
    cv = round(sd(value) / mean(value) * 100, 1)  # 变异系数 (%)
  ) |&gt;
  arrange(desc(cv))







Note变异系数（CV）



CV = (标准差 / 均值) × 100%，用于比较不同量纲变量的变异程度。CV &gt; 30% 通常认为变异较大。




20.5.2 分组统计

diversity |&gt;
  group_by(habitat) |&gt;
  summarise(
    n = n(),
    mean_richness = round(mean(richness), 1),
    sd_richness = round(sd(richness), 1),
    mean_shannon = round(mean(shannon), 2),
    mean_biomass = round(mean(biomass), 0)
  ) |&gt;
  arrange(desc(mean_richness))
